1426: 	SendNativeHistograms bool              `yaml:"send_native_histograms,omitempty"`
1427: 	RoundRobinDNS        bool              `yaml:"round_robin_dns,omitempty"`
1428: 	// ProtobufMessage specifies the protobuf message to use against the remote
1429: 	// receiver as specified in https://prometheus.io/docs/specs/remote_write_spec_2_0/
1430: 	ProtobufMessage remoteapi.WriteMessageType `yaml:"protobuf_message,omitempty"`
1431: 
