1447: // UnmarshalYAML implements the yaml.Unmarshaler interface.
1448: func (c *RemoteWriteConfig) UnmarshalYAML(unmarshal func(any) error) error {
1449: 	*c = DefaultRemoteWriteConfig
1450: 	type plain RemoteWriteConfig
1451: 	if err := unmarshal((*plain)(c)); err != nil {
1452: 		return err
1453: 	}
1454: 	if c.URL == nil {
1455: 		return errors.New("url for remote_write is empty")
1456: 	}
1457: 	for _, rlcfg := range c.WriteRelabelConfigs {
1458: 		if rlcfg == nil {
1459: 			return errors.New("empty or null relabeling rule in remote write config")
1460: 		}
1461: 	}
1462: 	if err := validateHeaders(c.Headers); err != nil {
1463: 		return err
1464: 	}
1465: 
1466: 	if err := c.ProtobufMessage.Validate(); err != nil {
1467: 		return fmt.Errorf("invalid protobuf_message value: %w", err)
1468: 	}
1469: 
1470: 	// The UnmarshalYAML method of HTTPClientConfig is not being called because it's not a pointer.
1471: 	// We cannot make it a pointer as the parser panics for inlined pointer structs.
1472: 	// Thus we just do its validation here.
1473: 	if err := c.HTTPClientConfig.Validate(); err != nil {
1474: 		return err
1475: 	}
1476: 
1477: 	return validateAuthConfigs(c)
1478: }
